import{c as r,Q as a,j as e,m as l}from"./chunks/framework.BIBjCrbN.js";const c=JSON.parse('{"title":"清华大学","description":"清华大学生物医学工程学院博士项目指南 — 导师信息、申请流程与2026年入学关键节点","frontmatter":{"title":"清华大学","description":"清华大学生物医学工程学院博士项目指南 — 导师信息、申请流程与2026年入学关键节点","data-collected":"2026-05-25T00:00:00.000Z","related-directions":["bci","bme","neuroscience","medical-physics"],"tags":["清华大学","北京",985,"C9"],"admission-year":2027},"headers":[],"relativePath":"universities/tsinghua.md","filePath":"universities/tsinghua.md","lastUpdated":1780110618000}'),n={name:"universities/tsinghua.md"};function i(o,t,s,d,h,g){return a(),e("div",null,[...t[0]||(t[0]=[l('<h1 id="清华大学" tabindex="-1">清华大学 <a class="header-anchor" href="#清华大学" aria-label="Permalink to &quot;清华大学&quot;">​</a></h1><blockquote><p><strong>最后更新</strong>: 2026年5月25日 | ⚠️ <strong>2027招生简章预计2026年7月发布</strong></p></blockquote><div class="warning custom-block"><p class="custom-block-title">清华第一批报名即将启动</p><p>清华是极少数采用&quot;7月第一批&quot;的高校。<strong>2027秋季入学第一批预计2026年7月启动</strong>，仅剩约2个月！ 建议<strong>6月底前准备好所有材���，7月第一时间联系导师并报名</strong>。</p></div><h2 id="学校概况" tabindex="-1">学校概况 <a class="header-anchor" href="#学校概况" aria-label="Permalink to &quot;学校概况&quot;">​</a></h2><p>清华大学在2025年QS世界大学排名中位列第14位，工程与技术学科全球前10。在生物医学工程领域，清华大学拥有国家重点学科，尤其在脑机接口、医学影像、微纳医学等方向处于国内领先地位。</p><p><strong>官方链接</strong>:</p><ul><li>学校官网: <a href="https://www.tsinghua.edu.cn" target="_blank" rel="noreferrer">https://www.tsinghua.edu.cn</a></li><li>研究生招生网: <a href="https://yz.tsinghua.edu.cn" target="_blank" rel="noreferrer">https://yz.tsinghua.edu.cn</a></li><li>研究生申请服务系统: <a href="https://yzbm.tsinghua.edu.cn" target="_blank" rel="noreferrer">https://yzbm.tsinghua.edu.cn</a></li><li>2026年博士招生简章: <a href="https://yz.tsinghua.edu.cn" target="_blank" rel="noreferrer">清华研招网</a></li></ul><h2 id="相关学院" tabindex="-1">相关学院 <a class="header-anchor" href="#相关学院" aria-label="Permalink to &quot;相关学院&quot;">​</a></h2><h3 id="_1-生物医学工程学院-院系代码-502" tabindex="-1">1. 生物医学工程学院（院系代码：502） <a class="header-anchor" href="#_1-生物医学工程学院-院系代码-502" aria-label="Permalink to &quot;1. 生物医学工程学院（院系代码：502）&quot;">​</a></h3><ul><li>学院官网: <a href="http://bme.tsinghua.edu.cn" target="_blank" rel="noreferrer">http://bme.tsinghua.edu.cn</a></li><li>招生咨询电话: 010-62782493</li><li>咨询邮箱: <a href="mailto:bmejx@tsinghua.edu.cn" target="_blank" rel="noreferrer">bmejx@tsinghua.edu.cn</a></li><li>招生专业: 083100 生物医学工程（学术学位博士）</li></ul><h3 id="_2-医学院" tabindex="-1">2. 医学院 <a class="header-anchor" href="#_2-医学院" aria-label="Permalink to &quot;2. 医学院&quot;">​</a></h3><ul><li>学院官网: <a href="https://www.med.tsinghua.edu.cn" target="_blank" rel="noreferrer">https://www.med.tsinghua.edu.cn</a></li><li>相关方向: 基础医学、临床医学、生物医学工程交叉</li></ul><h3 id="_3-生命科学学院" tabindex="-1">3. 生命科学学院 <a class="header-anchor" href="#_3-生命科学学院" aria-label="Permalink to &quot;3. 生命科学学院&quot;">​</a></h3><ul><li>相关方向: 神经生物学、细胞生物学</li></ul><h2 id="_2026年博士招生-—-生物医学工程学院" tabindex="-1">2026年博士招生 — 生物医学工程学院 <a class="header-anchor" href="#_2026年博士招生-—-生物医学工程学院" aria-label="Permalink to &quot;2026年博士招生 — 生物医学工程学院&quot;">​</a></h2><h3 id="招生方式" tabindex="-1">招生方式 <a class="header-anchor" href="#招生方式" aria-label="Permalink to &quot;招生方式&quot;">​</a></h3><p><strong>申请-审核制</strong>，可接收：普通博士生、硕博连读生、直博生（应届本科生推荐免试）</p><h3 id="申请时间" tabindex="-1">申请时间 <a class="header-anchor" href="#申请时间" aria-label="Permalink to &quot;申请时间&quot;">​</a></h3><table tabindex="0"><thead><tr><th>批次</th><th>时间</th></tr></thead><tbody><tr><td><strong>申请时间1</strong>（含专项计划）</td><td>2025年7月1日 12:00 — 7月28日 12:00</td></tr><tr><td><strong>申请时间2</strong>（如名额未满）</td><td>2025年11月1日 12:00 — 11月30日 16:00</td></tr></tbody></table><blockquote><p><strong>注意</strong>：所有专项计划（强军计划、少数民族骨干、对口支援等）仅在申请时间1招生。</p></blockquote><h3 id="申请材料" tabindex="-1">申请材料 <a class="header-anchor" href="#申请材料" aria-label="Permalink to &quot;申请材料&quot;">​</a></h3><ol><li>报考登记表（系统生成）</li><li>个人陈述</li><li>研究计划书</li><li>硕士和本科学历学位证书及成绩单</li><li><strong>两封副教授及以上职称专家推荐信</strong></li><li>英语水平证明</li><li>代表性学术成果</li><li>身份证/护照复印件</li></ol><h3 id="考核方式" tabindex="-1">考核方式 <a class="header-anchor" href="#考核方式" aria-label="Permalink to &quot;考核方式&quot;">​</a></h3><ul><li><strong>笔试</strong>：《专业英语》，2小时，满分100分（推免生免笔试）</li><li><strong>面试</strong>：约30分钟（推免生约20分钟），满分100分 <ul><li>英语口语能力</li><li>基本素养</li><li>学术能力</li><li>学术志趣</li></ul></li><li><strong>材料审查比</strong>：按 1:1.5 ~ 1:3 进入综合考核</li></ul><h3 id="_2026年特别通道" tabindex="-1">2026年特别通道 <a class="header-anchor" href="#_2026年特别通道" aria-label="Permalink to &quot;2026年特别通道&quot;">​</a></h3><p>新增面向<strong>海外高校中国籍优秀本科毕业生</strong>直接攻读博士学位的通道（GPA ≥ 3.5/4.0）。</p><hr><h2 id="重点课题组与导师" tabindex="-1">重点课题组与导师 <a class="header-anchor" href="#重点课题组与导师" aria-label="Permalink to &quot;重点课题组与导师&quot;">​</a></h2><h3 id="——-神经工程-脑机接口方向-——" tabindex="-1">—— 神经工程 / 脑机接口方向 —— <a class="header-anchor" href="#——-神经工程-脑机接口方向-——" aria-label="Permalink to &quot;—— 神经工程 / 脑机接口方向 ——&quot;">​</a></h3><h4 id="洪波-—-长聘教授、博导" tabindex="-1">洪波 — 长聘教授、博导 <a class="header-anchor" href="#洪波-—-长聘教授、博导" aria-label="Permalink to &quot;洪波 — 长聘教授、博导&quot;">​</a></h4><ul><li><strong>学院</strong>: 生物医学工程学院</li><li><strong>兼任</strong>: 为先书院院长</li><li><strong>个人主页</strong>: <a href="https://www.med.tsinghua.edu.cn/info/1142/2103.htm" target="_blank" rel="noreferrer">https://www.med.tsinghua.edu.cn/info/1142/2103.htm</a></li><li><strong>实验室</strong>: <a href="http://neuro.med.tsinghua.edu.cn/" target="_blank" rel="noreferrer">http://neuro.med.tsinghua.edu.cn/</a></li><li><strong>邮箱</strong>: <a href="mailto:hongbo@tsinghua.edu.cn" target="_blank" rel="noreferrer">hongbo@tsinghua.edu.cn</a></li><li><strong>电话</strong>: +86-10-62795985</li></ul><p><strong>研究方向</strong>:</p><ul><li><strong>脑机接口（BCI）</strong> — 核心方向，无线微创脑机接口 <strong>NEO 系统</strong></li><li>神经工程 — 神经信号解码、脑网络分析</li><li>语言智能 — 人脑语音语言处理机制</li><li>癫痫网络 — 颅内脑电与脑功能定位</li></ul><p><strong>核心成果 — NEO 系统</strong>: 洪波团队走出了独特的&quot;半侵入式&quot;（硬脑膜外）技术路线：</p><ul><li>电极置于硬脑膜外（不损伤神经组织），体内机嵌入颅骨</li><li>近场无线耦合供电（无需电池），高带宽双向无线信号传输</li><li>2023年10月：宣武医院完成全球首例无线微创脑机接口临床试验</li><li>2025年：全国12家医院多中心注册临床试验，已完成32例植入</li><li><strong>全球首款侵入式脑机接口医疗器械获批上市</strong></li><li>被 <em>Nature</em> 列为「2025年值得关注的科学事件」</li></ul><p><strong>代表性论文</strong>:</p><ol><li>人脑言语处理网络协同机制 — <em>Nature Neuroscience</em></li><li>微创脑机接口临床研究 — <em>Nature Communications</em></li><li>颅内脑电与语言解码 — <em>PNAS</em></li><li>高频脑电采集系统 — <em>NeuroImage</em></li></ol><p><strong>学术荣誉</strong>: 北京市科技新星、教育部新世纪优秀人才。指导创立博睿康（国内最早脑机接口产业化公司）。担任 <em>IEEE Transactions on Biomedical Engineering</em> 副主编。</p><p><strong>2026年博士生招生</strong>: 是（需确认具体名额）</p><hr><h4 id="song-sen-—-教授、博导" tabindex="-1">SONG SEN — 教授、博导 <a class="header-anchor" href="#song-sen-—-教授、博导" aria-label="Permalink to &quot;SONG SEN — 教授、博导&quot;">​</a></h4><ul><li><strong>学院</strong>: 生物医学工程学院</li><li><strong>研究方向</strong>: 神经工程与系统神经科学</li><li><strong>2026年招生</strong>: 待确认</li></ul><hr><h4 id="苑克鑫-—-教授、博导" tabindex="-1">苑克鑫 — 教授、博导 <a class="header-anchor" href="#苑克鑫-—-教授、博导" aria-label="Permalink to &quot;苑克鑫 — 教授、博导&quot;">​</a></h4><ul><li><strong>学院</strong>: 生物医学工程学院</li><li><strong>研究方向</strong>: 神经工程与系统神经科学</li><li><strong>2026年招生</strong>: 待确认</li></ul><hr><h3 id="——-生物医学成像与图像处理方向-——" tabindex="-1">—— 生物医学成像与图像处理方向 —— <a class="header-anchor" href="#——-生物医学成像与图像处理方向-——" aria-label="Permalink to &quot;—— 生物医学成像与图像处理方向 ——&quot;">​</a></h3><table tabindex="0"><thead><tr><th>导师</th><th>研究方向</th><th>主页</th></tr></thead><tbody><tr><td><strong>郭华</strong></td><td>医学影像、MRI物理与工程</td><td>—</td></tr><tr><td><strong>罗建文</strong></td><td>超声成像、弹性成像</td><td>—</td></tr><tr><td><strong>陈慧军</strong></td><td>医学影像处理与分析</td><td>—</td></tr><tr><td><strong>廖洪恩</strong></td><td>医学影像引导治疗、微创诊疗</td><td>—</td></tr><tr><td><strong>田启源</strong></td><td>计算影像、光学成像</td><td>—</td></tr><tr><td><strong>张洋</strong></td><td>医学图像处理、AI辅助诊断</td><td>—</td></tr></tbody></table><h3 id="——-微纳医学与组织工程方向-——" tabindex="-1">—— 微纳医学与组织工程方向 —— <a class="header-anchor" href="#——-微纳医学与组织工程方向-——" aria-label="Permalink to &quot;—— 微纳医学与组织工程方向 ——&quot;">​</a></h3><table tabindex="0"><thead><tr><th>导师</th><th>研究方向</th><th>备注</th></tr></thead><tbody><tr><td><strong>程京</strong></td><td>生物芯片、精准医学（院士）</td><td>不招直博生</td></tr><tr><td><strong>杜亚楠</strong></td><td>生物材料、组织工程</td><td>—</td></tr><tr><td><strong>戴小川</strong></td><td>神经工程、柔性电子</td><td>—</td></tr><tr><td><strong>马恺</strong></td><td>纳米医学</td><td>—</td></tr><tr><td><strong>李舟</strong></td><td>纳米生物传感器</td><td>—</td></tr></tbody></table><h3 id="——-生物医学仪器与系统方向-——" tabindex="-1">—— 生物医学仪器与系统方向 —— <a class="header-anchor" href="#——-生物医学仪器与系统方向-——" aria-label="Permalink to &quot;—— 生物医学仪器与系统方向 ——&quot;">​</a></h3><table tabindex="0"><thead><tr><th>导师</th><th>研究方向</th></tr></thead><tbody><tr><td><strong>程京</strong></td><td>生物芯片系统（院士）</td></tr><tr><td><strong>黄国亮</strong></td><td>生物医学仪器、微流控</td></tr><tr><td><strong>廖洪恩</strong></td><td>微创诊疗器械</td></tr></tbody></table><hr><h2 id="奖学金" tabindex="-1">奖学金 <a class="header-anchor" href="#奖学金" aria-label="Permalink to &quot;奖学金&quot;">​</a></h2><ul><li><strong>清华未来学者奖学金</strong>：面向优秀博士生，额外奖励</li><li><strong>清华学堂人才培养计划</strong>：部分学科有专项</li><li>导师助研津贴通常较为充足（清华科研经费雄厚）</li><li>博士生月收入约 5000-8000 元（含国家助学金+学校奖学金+导师津贴）</li></ul><hr><h2 id="针对你的申请建议" tabindex="-1">针对你的申请建议 <a class="header-anchor" href="#针对你的申请建议" aria-label="Permalink to &quot;针对你的申请建议&quot;">​</a></h2><ol><li><strong>洪波课题组是最佳匹配目标之一</strong>：你的神经技术背景（脑类器官钙成像、EMG信号处理）与洪波团队的BCI/神经信号解码直接对口</li><li><strong>注意申请时间</strong>：第一批2025年7月1日-28日，需要在此之前准备好全部材料</li><li><strong>国际化背景是加分项</strong>：清华高度重视国际化，帝国理工硕士+英国本科的教育背景有显著优势</li><li><strong>提前联系导师</strong>：BCI方向竞争激烈，建议2025年5-6月发送联系邮件</li><li><strong>海外直博通道</strong>：可关注面向海外高校毕业生的直博通道</li></ol><hr><h2 id="信息来源" tabindex="-1">信息来源 <a class="header-anchor" href="#信息来源" aria-label="Permalink to &quot;信息来源&quot;">​</a></h2><ul><li><a href="https://yz.tsinghua.edu.cn" target="_blank" rel="noreferrer">清华研招网</a> — 2026年博士招生简章（访问日期: 2026-05-25）</li><li><a href="http://bme.tsinghua.edu.cn" target="_blank" rel="noreferrer">清华BME学院</a> — 学院官网（访问日期: 2026-05-25）</li><li><a href="https://www.med.tsinghua.edu.cn/info/1142/2103.htm" target="_blank" rel="noreferrer">洪波教授主页</a> — 导师详情（访问日期: 2026-05-25）</li></ul><hr><p><em>本页面信息采集于2026年5月，请以清华大学研究生院官网最新公告为准。</em></p><p><em>下次更新建议: 2026年8月（2027年入学申请季开始前）</em></p>',64)])])}const b=r(n,[["render",i]]);export{c as __pageData,b as default};
